package project

import (
	"bufio"
	"context"
	"fmt"
	"os"
	"strings"

	"github.com/usenurge/nurgesh/internal/connector"
)

type connectStep struct {
	credentials string
}

func (s *connectStep) Name() string { return "Stack connected" }

func (s *connectStep) Done() (bool, error) {
	cfg, err := Load()
	if err != nil {
		return false, nil // config might not exist yet in a fresh run
	}
	// Done if at least Gmail is connected
	if cs, ok := cfg.Connectors["gmail"]; ok && cs.Connected {
		return true, nil
	}
	return false, nil
}

func (s *connectStep) Run() error {
	cfg, err := Load()
	if err != nil {
		return fmt.Errorf("loading config: %w", err)
	}

	registry := connector.DefaultRegistry()
	reader := bufio.NewReader(os.Stdin)

	fmt.Println()
	fmt.Println("  Connect your stack:")

	for {
		// Show menu
		fmt.Println()
		fmt.Println("    Email (required)")
		for i, c := range registry {
			if c.Type != "email" {
				continue
			}
			status := ""
			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
				status = fmt.Sprintf(" \033[32m✓\033[0m %s", cs.Account)
			}
			fmt.Printf("      [%d] %s%s\n", i+1, c.Name, status)
		}

		fmt.Println()
		fmt.Println("    CRM (optional — enriches contacts with deal & pipeline data)")
		for i, c := range registry {
			if c.Type != "crm" {
				continue
			}
			status := ""
			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
				status = fmt.Sprintf(" \033[32m✓\033[0m %s", cs.Account)
			}
			fmt.Printf("      [%d] %s%s\n", i+1, c.Name, status)
		}

		fmt.Println()
		fmt.Print("    [done] Finish connecting\n\n  > ")

		input, err := reader.ReadString('\n')
		if err != nil {
			return fmt.Errorf("reading input: %w", err)
		}
		input = strings.TrimSpace(input)

		if input == "done" {
			// Check Gmail is connected
			if cs, ok := cfg.Connectors["gmail"]; !ok || !cs.Connected {
				fmt.Println()
				fmt.Print("  Gmail is required — it's how nurge reads your outbound history.\n  Connect now? [Y/n] ")
				yn, _ := reader.ReadString('\n')
				yn = strings.TrimSpace(strings.ToLower(yn))
				if yn == "n" || yn == "no" {
					return fmt.Errorf("gmail is required to use nurge")
				}
				input = "1" // fall through to connect Gmail
			} else {
				break
			}
		}

		// Parse selection
		var idx int
		if _, err := fmt.Sscanf(input, "%d", &idx); err != nil || idx < 1 || idx > len(registry) {
			fmt.Println("  Invalid selection. Try again.")
			continue
		}

		def := registry[idx-1]
		conn := def.New(s.credentials)

		fmt.Printf("  Opening browser for %s...\n", def.Name)

		result, err := conn.Connect(context.Background())
		if err != nil {
			fmt.Printf("  \033[31m✗\033[0m %s: %v\n", def.Name, err)
			if def.Required {
				return fmt.Errorf("%s connection failed: %w", def.Name, err)
			}
			fmt.Printf("  Skipping %s. You can connect later with `nurge connect %s`\n", def.Name, def.ID)
			continue
		}

		// Save connector state
		if err := SetConnector(def.ID, def.Type, result.Account); err != nil {
			return fmt.Errorf("saving %s config: %w", def.Name, err)
		}

		// Reload config
		cfg, _ = Load()

		fmt.Printf("  \033[32m✓\033[0m %s connected (%s)\n", def.Name, result.Account)
	}

	// Print summary
	var connected []string
	for _, c := range registry {
		if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
			connected = append(connected, c.Name)
		}
	}
	fmt.Printf("\n  Connected: %s\n", strings.Join(connected, ", "))

	// Tip if no CRM
	hasCRM := false
	for _, c := range registry {
		if c.Type == "crm" {
			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
				hasCRM = true
				break
			}
		}
	}
	if !hasCRM {
		fmt.Println("  Tip: You can connect a CRM later with `nurge connect hubspot`")
	}

	return nil
}

package project

import (
	"fmt"
	"os"
	"os/exec"
	"syscall"
)

type nextStepStep struct{}

func (s *nextStepStep) Name() string { return "" } // no label, just prints

func (s *nextStepStep) Done() (bool, error) { return false, nil }

func (s *nextStepStep) Run() error {
	fmt.Println()

	if isInsideClaudeCode() {
		fmt.Println("  You're ready. Run:")
		fmt.Println("    /nurge:setup")
		fmt.Println()
		return nil
	}

	if isClaudeInstalled() {
		fmt.Println("  Launching Claude Code...")
		fmt.Println()
		return launchClaude()
	}

	fmt.Println("  Almost there! Install Claude Code first:")
	fmt.Println("    https://claude.ai/code")
	fmt.Println()
	fmt.Println("  Then run:")
	fmt.Println("    claude -p \"/nurge:setup\"")
	fmt.Println()
	return nil
}

func isInsideClaudeCode() bool {
	return os.Getenv("CLAUDE_CODE") != ""
}

func isClaudeInstalled() bool {
	_, err := exec.LookPath("claude")
	return err == nil
}

// launchClaude replaces the current process with claude in interactive mode.
// SessionStart hooks handle the rest — banner shows status, prompt guides Claude.
func launchClaude() error {
	claudePath, err := exec.LookPath("claude")
	if err != nil {
		return fmt.Errorf("claude not found: %w", err)
	}

	// syscall.Exec replaces the nurge process with claude — clean handoff
	return syscall.Exec(claudePath, []string{"claude"}, os.Environ())
}

