50→	Long:  "Nurge is an outbound sales tool that learns from your sent email history.",
51→}
52→
53→var versionCmd = &cobra.Command{
54→	Use:         "version",
55→	Short:       "Print the version of nurge",
56→	Annotations: map[string]string{"skipAuth": "true"},
57→	Run: func(cmd *cobra.Command, args []string) {
