62→// shouldSkipAuth walks the command tree to check if any command in the
63→// chain has the skipAuth annotation. This handles cases like
64→// "nurge account login" where account has skipAuth.
65→func shouldSkipAuth(cmd *cobra.Command) bool {
66→	for c := cmd; c != nil; c = c.Parent() {
67→		if c.Annotations != nil && c.Annotations["skipAuth"] == "true" {
68→			return true
69→		}
70→	}
71→	return false
72→}
