78→		if shouldSkipAuth(cmd) ||
79→			cmd.Name() == "help" ||
80→			cmd.Name() == "completion" {
81→			return nil
82→		}
83→		_, err := account.EnsureAuth(GetConvexURL(), GetDashboardURL())
84→		return err
