 78→// isDirEmpty returns true if dir contains no entries except allowed ones
 79→// (.nurge, .git, .gitignore, .DS_Store, .claude).
 80→func isDirEmpty(dir string) (bool, error) {
 81→	allowed := map[string]bool{
 82→		".nurge":     true,
 83→		".git":       true,
 84→		".gitignore": true,
 85→		".DS_Store":  true,
 86→		".claude":    true,
 87→	}
 88→
 89→	entries, err := os.ReadDir(dir)
 90→	if err != nil {
 91→		return false, err
 92→	}
 93→	for _, e := range entries {
 94→		name := strings.TrimSuffix(e.Name(), "/")
 95→		if !allowed[name] {
 96→			return false, nil
 97→		}
 98→	}
 99→	return true, nil
100→}
