 12→
 13→type connectStep struct {
 14→	credentials string
 15→}
 16→
 17→func (s *connectStep) Name() string { return "Stack connected" }
 18→
 19→func (s *connectStep) Done() (bool, error) {
 20→	cfg, err := Load()
 21→	if err != nil {
 22→		return false, nil // config might not exist yet in a fresh run
 23→	}
 24→	// Done if at least Gmail is connected
 25→	if cs, ok := cfg.Connectors["gmail"]; ok && cs.Connected {
 26→		return true, nil
 27→	}
 28→	return false, nil
 29→}
 30→
 31→func (s *connectStep) Run() error {
 32→	cfg, err := Load()
 33→	if err != nil {
 34→		return fmt.Errorf("loading config: %w", err)
 35→	}
 36→
 37→	registry := connector.DefaultRegistry()
 38→	reader := bufio.NewReader(os.Stdin)
 39→
 40→	fmt.Println()
 41→	fmt.Println("  Connect your stack:")
 42→
 43→	for {
 44→		// Show menu
 45→		fmt.Println()
 46→		fmt.Println("    Email (required)")
 47→		for i, c := range registry {
 48→			if c.Type != "email" {
 49→				continue
 50→			}
 51→			status := ""
 52→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
 53→				status = fmt.Sprintf(" \033[32m✓\033[0m %s", cs.Account)
 54→			}
 55→			fmt.Printf("      [%d] %s%s\n", i+1, c.Name, status)
 56→		}
 57→
 58→		fmt.Println()
 59→		fmt.Println("    CRM (optional — enriches contacts with deal & pipeline data)")
 60→		for i, c := range registry {
 61→			if c.Type != "crm" {
 62→				continue
 63→			}
 64→			status := ""
 65→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
 66→				status = fmt.Sprintf(" \033[32m✓\033[0m %s", cs.Account)
 67→			}
 68→			fmt.Printf("      [%d] %s%s\n", i+1, c.Name, status)
 69→		}
 70→
 71→		fmt.Println()
 72→		fmt.Print("    [done] Finish connecting\n\n  > ")
 73→
 74→		input, err := reader.ReadString('\n')
 75→		if err != nil {
 76→			return fmt.Errorf("reading input: %w", err)
 77→		}
 78→		input = strings.TrimSpace(input)
 79→
 80→		if input == "done" {
 81→			// Check Gmail is connected
 82→			if cs, ok := cfg.Connectors["gmail"]; !ok || !cs.Connected {
 83→				fmt.Println()
 84→				fmt.Print("  Gmail is required — it's how nurge reads your outbound history.\n  Connect now? [Y/n] ")
 85→				yn, _ := reader.ReadString('\n')
 86→				yn = strings.TrimSpace(strings.ToLower(yn))
 87→				if yn == "n" || yn == "no" {
 88→					return fmt.Errorf("gmail is required to use nurge")
 89→				}
 90→				input = "1" // fall through to connect Gmail
 91→			} else {
 92→				break
 93→			}
 94→		}
 95→
 96→		// Parse selection
 97→		var idx int
 98→		if _, err := fmt.Sscanf(input, "%d", &idx); err != nil || idx < 1 || idx > len(registry) {
 99→			fmt.Println("  Invalid selection. Try again.")
100→			continue
101→		}
102→
103→		def := registry[idx-1]
104→		conn := def.New(s.credentials)
105→
106→		fmt.Printf("  Opening browser for %s...\n", def.Name)
107→
108→		result, err := conn.Connect(context.Background())
109→		if err != nil {
110→			fmt.Printf("  \033[31m✗\033[0m %s: %v\n", def.Name, err)
111→			if def.Required {
112→				return fmt.Errorf("%s connection failed: %w", def.Name, err)
113→			}
114→			fmt.Printf("  Skipping %s. You can connect later with `nurge connect %s`\n", def.Name, def.ID)
115→			continue
116→		}
117→
118→		// Save connector state
119→		if err := SetConnector(def.ID, def.Type, result.Account); err != nil {
120→			return fmt.Errorf("saving %s config: %w", def.Name, err)
121→		}
122→
123→		// Reload config
124→		cfg, _ = Load()
125→
126→		fmt.Printf("  \033[32m✓\033[0m %s connected (%s)\n", def.Name, result.Account)
127→	}
128→
129→	// Print summary
130→	var connected []string
131→	for _, c := range registry {
132→		if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
133→			connected = append(connected, c.Name)
134→		}
135→	}
136→	fmt.Printf("\n  Connected: %s\n", strings.Join(connected, ", "))
137→
138→	// Tip if no CRM
139→	hasCRM := false
140→	for _, c := range registry {
141→		if c.Type == "crm" {
142→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
143→				hasCRM = true
144→				break
145→			}
146→		}
147→	}
148→	if !hasCRM {
149→		fmt.Println("  Tip: You can connect a CRM later with `nurge connect hubspot`")
150→	}
151→
152→	return nil
153→}
