15→func (s *gitignoreStep) Done() (bool, error) {
16→	data, err := os.ReadFile(".gitignore")
17→	if err != nil {
18→		if os.IsNotExist(err) {
19→			return false, nil
20→		}
21→		return false, err
22→	}
23→	for _, line := range strings.Split(string(data), "\n") {
