34→		return fmt.Errorf("opening .gitignore: %w", err)
35→	}
36→	defer f.Close()
37→
38→	_, err = f.WriteString("\n# nurge\n" + gitignoreEntry + "\n")
39→	if err != nil {
40→		return fmt.Errorf("writing .gitignore: %w", err)
41→	}
