 83→func gatherStatus() *sessionStatus {
 84→	s := &sessionStatus{}
 85→
 86→	// Load config (graceful — may not exist)
 87→	cfg, err := project.Load()
 88→	if err == nil {
 89→		s.configLoaded = true
 90→		s.setupCompleted = cfg.SetupCompleted
 91→		s.connectors = cfg.Connectors
 92→	}
