131→// runSessionStart outputs JSON with systemMessage (visible banner) and
132→// additionalContext (LLM context) for the SessionStart hook.
133→// Also captures the session in DB + log.
134→func runSessionStart() error {
135→	// Read stdin (Claude Code sends session info)
136→	input, _ := session.ReadStdin()
137→
138→	// Capture session in DB (graceful — don't fail the hook if DB is missing)
139→	if input != nil && input.SessionID != "" && db.Exists() {
140→		if d, err := db.Open(); err == nil {
141→			db.EnsureSessionTables(d)
142→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
143→			session.AddEvent(d, input.SessionID, "session_start", input)
144→			d.Close()
145→		}
146→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
147→		session.FlushLog()
148→	}
149→
150→	s := gatherStatus()
151→
152→	banner := buildBanner(s)
153→	context := buildPromptContext(s)
154→
155→	out := hookOutput{
156→		SystemMessage: banner,
157→		HookSpecificOut: &hookSpecificOut{
158→			HookEventName:     "SessionStart",
159→			AdditionalContext: context,
160→		},
161→	}
162→
163→	enc := json.NewEncoder(os.Stdout)
164→	return enc.Encode(out)
165→}
