192→// runStop captures a stop event and creates a checkpoint.
193→func runStop() error {
194→	input, err := session.ReadStdin()
195→	if err != nil || input == nil || input.SessionID == "" {
196→		return nil
197→	}
198→
199→	if !db.Exists() {
200→		return nil
