203→	if err != nil {
204→		return nil
205→	}
206→	defer d.Close()
207→
208→	db.EnsureSessionTables(d)
209→	session.AddEvent(d, input.SessionID, "stop", input)
210→	if len(input.ModifiedFiles) > 0 {
211→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
212→	}
213→
214→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
215→	session.FlushLog()
216→	return nil
