290→func buildPromptContext(s *sessionStatus) string {
291→	var b strings.Builder
292→
293→	if !s.configLoaded || !s.setupCompleted {
294→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
295→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
296→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
