300→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
301→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced. %d skills active.\n", formatCount(s.emailTotal), s.skillCount)
302→	b.WriteString("Rules:\n")
303→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
304→	b.WriteString("- For ICP and product context, run: nurge config show --format json\n")
