306→	b.WriteString("- For email stats, run: nurge emails stats --format json\n")
307→	b.WriteString("- When writing outbound emails, always run: nurge send")
308→
309→	if len(s.skillNames) > 0 {
310→		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
311→	}
312→
313→	return b.String()
