104→func saveToken(path string, token *oauth2.Token) error {
105→	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_TRUNC, 0600)
106→	if err != nil {
107→		return err
108→	}
109→	defer f.Close()
110→	return json.NewEncoder(f).Encode(token)
