package project

import (
	"fmt"
	"os"
)

// Options holds CLI flags for nurge init.
type Options struct {
	Credentials    string
	SkipConnectors bool
	SkipHooks      bool
	Force          bool
	Verbose        bool
}

// Step is the interface each init step implements.
type Step interface {
	Name() string
	Done() (bool, error)
	Run() error
}

// Run executes all init steps in order.
func Run(opts Options) error {
	fmt.Println()
	fmt.Println("  nurge — outbound that learns")
	fmt.Println()

	steps := buildSteps(opts)

	for _, s := range steps {
		if !opts.Force {
			done, err := s.Done()
			if err != nil {
				printFail(s.Name(), err)
				return err
			}
			if done {
				printSkip(s.Name())
				continue
			}
