// isDirEmpty returns true if dir contains no entries except allowed ones
// (.nurge, .git, .gitignore, .DS_Store, .claude).
func isDirEmpty(dir string) (bool, error) {
	allowed := map[string]bool{
		".nurge":     true,
		".git":       true,
		".gitignore": true,
		".DS_Store":  true,
		".claude":    true,
	}

	entries, err := os.ReadDir(dir)
	if err != nil {
		return false, err
	}
	for _, e := range entries {
		name := strings.TrimSuffix(e.Name(), "/")
		if !allowed[name] {
			return false, nil
		}
	}
	return true, nil
}

