package connector

import (
	"context"
	"encoding/json"
	"fmt"
	"os"

	"golang.org/x/oauth2"
	"golang.org/x/oauth2/google"
	"google.golang.org/api/gmail/v1"
	"google.golang.org/api/option"
)

const (
	gmailTokenPath = ".nurge/connectors/gmail/token.json"
	gmailCredsPath = ".nurge/connectors/gmail/credentials.json"
)

type gmailConnector struct {
	credentials string // optional override path for credentials.json
}

// NewGmail creates a new Gmail connector.
func NewGmail(credentials string) Connector {
	return &gmailConnector{credentials: credentials}
}

func (g *gmailConnector) ID() string   { return "gmail" }
func (g *gmailConnector) Name() string { return "Gmail" }
func (g *gmailConnector) Type() string { return "email" }

func (g *gmailConnector) Connect(ctx context.Context) (*Result, error) {
	// Load OAuth client credentials: custom path > local file > bundled
	credsData, err := g.loadCredentials()
	if err != nil {
		return nil, err
	}

	oauthCfg, err := google.ConfigFromJSON(credsData,
		gmail.GmailReadonlyScope,
		gmail.GmailSendScope,
		gmail.GmailModifyScope,
	)
	if err != nil {
		return nil, fmt.Errorf("parsing credentials: %w", err)
	}

	// Run shared OAuth flow
	token, err := OAuthFlow(ctx, oauthCfg, oauth2.SetAuthURLParam("prompt", "select_account"))
	if err != nil {
		return nil, err
	}

	// Save token
	if err := os.MkdirAll(".nurge/connectors/gmail", 0755); err != nil {
		return nil, fmt.Errorf("creating gmail connector dir: %w", err)
	}
	if err := saveToken(gmailTokenPath, token); err != nil {
		return nil, fmt.Errorf("saving token: %w", err)
	}

	// Get the user's email address
	client := oauthCfg.Client(ctx, token)
	srv, err := gmail.NewService(ctx, option.WithHTTPClient(client))
	if err != nil {
		return nil, fmt.Errorf("creating Gmail service: %w", err)
	}

	profile, err := srv.Users.GetProfile("me").Do()
	if err != nil {
		return nil, fmt.Errorf("getting Gmail profile: %w", err)
	}

	return &Result{
		Account: profile.EmailAddress,
		Token:   token,
	}, nil
}

func (g *gmailConnector) loadCredentials() ([]byte, error) {
	// 1. Explicit path from --credentials flag
	if g.credentials != "" {
		data, err := os.ReadFile(g.credentials)
		if err != nil {
			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
		}
		return data, nil
	}

	// 2. Local file in project
	if data, err := os.ReadFile(gmailCredsPath); err == nil {
		return data, nil
	}

	// 3. Bundled credentials
	if len(BundledCredentials) > 0 {
		return BundledCredentials, nil
	}

	return nil, fmt.Errorf("no Gmail credentials found — run `nurge init --credentials /path/to/credentials.json`")
}

func saveToken(path string, token *oauth2.Token) error {
	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_TRUNC, 0600)
	if err != nil {
		return err
	}
	defer f.Close()
	return json.NewEncoder(f).Encode(token)
}

