package connector

import (
	"context"
	"fmt"
	"time"

	"github.com/usenurge/nurgesh/internal/util"
	"golang.org/x/oauth2"
)

// OAuthFlow runs the shared OAuth2 local-server flow.
// It starts a local HTTP server, opens the browser to the auth URL,
// waits for the callback with the auth code, and exchanges it for tokens.
func OAuthFlow(ctx context.Context, cfg *oauth2.Config, authOpts ...oauth2.AuthCodeOption) (*oauth2.Token, error) {
	port, resultCh, errCh, cleanup, err := util.ListenAndWait(120 * time.Second)
	if err != nil {
		return nil, err
	}
	defer cleanup()

	cfg.RedirectURL = fmt.Sprintf("http://localhost:%d/callback", port)
	authURL := cfg.AuthCodeURL("nurge-state", authOpts...)

	if err := util.OpenBrowser(authURL); err != nil {
		return nil, fmt.Errorf("opening browser: %w\n  Please open this URL manually:\n  %s", err, authURL)
	}

	select {
	case result := <-resultCh:
		code := result.Values.Get("code")
		if code == "" {
			return nil, fmt.Errorf("no authorization code received")
		}
		token, err := cfg.Exchange(ctx, code)
		if err != nil {
			return nil, fmt.Errorf("exchanging code for token: %w", err)
		}
		return token, nil
	case err := <-errCh:
		return nil, err
	case <-ctx.Done():
		return nil, ctx.Err()
	}
}

package util

import (
	"fmt"
	"net"
	"net/http"
	"net/url"
	"time"
)

// Result holds the query parameters from the callback.
type Result struct {
	Values url.Values
}

// ListenAndWait starts a local HTTP server on a random port, waits for a
// single request to /callback, and returns the query parameters.
// The caller must call the returned cleanup function when done.
func ListenAndWait(timeout time.Duration) (port int, resultCh <-chan Result, errCh <-chan error, cleanup func(), err error) {
	listener, err := net.Listen("tcp", "localhost:0")
	if err != nil {
		return 0, nil, nil, nil, fmt.Errorf("finding free port: %w", err)
	}
	port = listener.Addr().(*net.TCPAddr).Port

	rCh := make(chan Result, 1)
	eCh := make(chan error, 1)

	mux := http.NewServeMux()
	mux.HandleFunc("/callback", func(w http.ResponseWriter, r *http.Request) {
		errParam := r.URL.Query().Get("error")
		if errParam != "" {
			fmt.Fprintf(w, "<html><body><h2>Error</h2><p>%s</p><p>You can close this tab.</p></body></html>", errParam)
			eCh <- fmt.Errorf("callback error: %s", errParam)
			return
		}
		fmt.Fprintf(w, "<html><body><h2>Success!</h2><p>You can close this tab and return to the terminal.</p></body></html>")
		rCh <- Result{Values: r.URL.Query()}
	})

	server := &http.Server{Handler: mux}
	go server.Serve(listener)

	cleanupFn := func() {
		server.Close()
	}

	// Timeout goroutine
	go func() {
		<-time.After(timeout)
		eCh <- fmt.Errorf("timed out after %s", timeout)
		server.Close()
	}()

	return port, rCh, eCh, cleanupFn, nil
}

package account

import (
	"crypto/rand"
	"errors"
	"fmt"
	"math/big"
	"os"
	"time"

	"github.com/usenurge/nurgesh/internal/util"
)

const (
	cacheTTL     = 5 * time.Minute
	gracePeriod  = 1 * time.Hour
	loginTimeout = 120 * time.Second
)

// EnsureAuth checks for a valid auth token. If not found or invalid,
// runs the interactive browser login flow.
// All status messages are printed to stderr so stdout stays clean for --format json.
func EnsureAuth(convexURL, dashboardURL string) (*User, error) {
	af, err := LoadAuth()
	if err == nil && af.Token != "" {
		// Check local cache
		if af.ValidatedAt != "" {
			validatedAt, _ := time.Parse(time.RFC3339, af.ValidatedAt)
			age := time.Since(validatedAt)

			if age < cacheTTL {
				// Recently validated, skip network call
				return &User{Email: af.Email, Name: af.Name}, nil
			}
		}

		// Validate against Convex
		client := NewConvexClient(convexURL)
		user, valErr := client.ValidateToken(af.Token)
		if valErr == nil {
			// Update validated_at
			af.ValidatedAt = time.Now().UTC().Format(time.RFC3339)
			SaveAuth(af) // best effort
			return user, nil
		}

		// Distinguish: token definitively invalid vs network error
		if errors.Is(valErr, ErrTokenInvalid) {
			// Token is invalid on server — go straight to login, no grace period
			return Login(convexURL, dashboardURL)
		}

		// Network error — check grace period
		if af.ValidatedAt != "" {
			validatedAt, _ := time.Parse(time.RFC3339, af.ValidatedAt)
			if time.Since(validatedAt) < gracePeriod {
				fmt.Fprintf(os.Stderr, "  Warning: could not reach Nurge servers, using cached auth\n")
				return &User{Email: af.Email, Name: af.Name}, nil
			}
		}

		// Grace period expired and can't reach server
		return nil, fmt.Errorf("could not validate auth token (no internet?). Try again or run `nurge account login`")
	}

	// No valid token — start login flow
	return Login(convexURL, dashboardURL)
}

// Login runs the interactive browser-based login flow.
func Login(convexURL, dashboardURL string) (*User, error) {
	// Generate state parameter
	state := generateState()

	// Start local callback server (binds before opening browser)
	port, resultCh, errCh, cleanup, err := util.ListenAndWait(loginTimeout)
	if err != nil {
		return nil, fmt.Errorf("starting callback server: %w", err)
	}
	defer cleanup()

	// Open browser to dashboard
	authURL := fmt.Sprintf("%s/cli-auth?port=%d&state=%s", dashboardURL, port, state)
	fmt.Fprintf(os.Stderr, "  Opening browser to log in...\n")
	if err := util.OpenBrowser(authURL); err != nil {
		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", authURL)
	}

	// Wait for callback
	select {
	case result := <-resultCh:
		// Verify state
		if result.Values.Get("state") != state {
			return nil, fmt.Errorf("state mismatch — possible CSRF attack")
		}

		code := result.Values.Get("code")
		if code == "" {
			return nil, fmt.Errorf("no auth code received")
		}

		// Exchange code for token
		client := NewConvexClient(convexURL)
		resp, err := client.ExchangeCode(code)
		if err != nil {
			return nil, fmt.Errorf("exchanging auth code: %w", err)
		}

		// Save auth file
		now := time.Now().UTC().Format(time.RFC3339)
		af := &AuthFile{
			Token:       resp.Token,
			Email:       resp.Email,
			Name:        resp.Name,
			CreatedAt:   now,
			ValidatedAt: now,
		}
		if err := SaveAuth(af); err != nil {
			return nil, fmt.Errorf("saving auth: %w", err)
		}

		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Logged in as %s\n", resp.Email)
		return &User{Email: resp.Email, Name: resp.Name}, nil

	case err := <-errCh:
		return nil, err
	}
}

// Logout revokes the token and deletes local auth file.
func Logout(convexURL string) error {
	af, err := LoadAuth()
	if err != nil {
		return fmt.Errorf("not logged in")
	}

	// Revoke on server (best effort)
	client := NewConvexClient(convexURL)
	_ = client.RevokeToken(af.Token)

	// Delete local auth file
	if err := DeleteAuth(); err != nil {
		return fmt.Errorf("deleting auth file: %w", err)
	}

	fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Logged out\n")
	return nil
}

// generateState creates a cryptographically random state string for CSRF protection.
func generateState() string {
	const chars = "REDACTED"
	b := make([]byte, 32)
	for i := range b {
		n, _ := rand.Int(rand.Reader, big.NewInt(int64(len(chars))))
		b[i] = chars[n.Int64()]
	}
	return string(b)
}
